              <text fill="#ff0000" font-size="19" font-weight="bold" font-family="SimHei, Arial, sans-serif" transform="rotate(-115 100 100)">
                <textPath href="#companyNamePath" startOffset="0%" text-anchor="start" side="top" letter-spacing="1.5">
                  无锡泰坦福新材料有限公司
                </textPath>
              </text>
              
              <!-- 中心红色五角星 -->
              <polygon points="100,60 108,80 130,80 115,95 122,115 100,103 78,115 85,95 70,80 92,80" fill="#ff0000" />
              
